+```javascript
+const { JjWrapper } = require('agentic-jujutsu');
+
+const jj = new JjWrapper();
+
+// Basic operations
+await jj.status();
+await jj.newCommit('Add feature');
+await jj.log(10);
+
+// Self-learning trajectory
+const id = jj.startTrajectory('Implement authentication');
